import { useState, useDeferredValue } from 'react'

const ALL = Array.from({ length: 3000 }, (_, i) => '项目 ' + i)

export default function App() {
  const [val, setVal] = useState('')
  const deferred = useDeferredValue(val)
  const isStale = deferred !== val
  const list = ALL.filter((x) => x.includes(deferred))
  return (
    <div style={{ padding: 12 }}>
      <input value={val} onChange={(e) => setVal(e.target.value)} placeholder="搜索" />
      <ul style={{ height: 160, overflow: 'auto', opacity: isStale ? 0.4 : 1, transition: 'opacity .3s' }}>
        {list.slice(0, 100).map((x) => (
          <li key={x}>{x}</li>
        ))}
      </ul>
    </div>
  )
}
